export class Proficiency {
    constructor(bonus = 0) {
        this.bonus = bonus;
        this.values = [0, 1, 2];
    }
    next() {
        const next = this.values.indexOf(this.bonus) + 1;
        this.bonus = this.values[next > this.values.length - 1 ? 0 : next];
        return this.bonus;
    }
}
export class Ability {
    constructor(name) {
        this.name = name;
        this.score = 10;
        this.saveProficiency = false;
    }
}
export class AbilityScores {
    constructor(clazz) {
        this.str = new Ability("strength");
        this.dex = new Ability("dexterity");
        this.con = new Ability("constitution");
        this.int = new Ability("intelligence");
        this.wis = new Ability("wisdom");
        this.cha = new Ability("charisma");
        // Prepopulate save proficiencies from class definition.
        clazz === null || clazz === void 0 ? void 0 : clazz.proficiency.forEach((p) => (this[p].saveProficiency = true));
    }
}
export class Skill {
    constructor(name, type) {
        this.name = name;
        this.type = type;
        this.proficiency = new Proficiency();
    }
}
export class Skills {
    constructor(skills) {
        this.ath = new Skill("athletics", "str");
        this.acr = new Skill("acrobatics", "dex");
        this.sle = new Skill("sleight of hand", "dex");
        this.ste = new Skill("stealth", "dex");
        this.arc = new Skill("arcana", "int");
        this.his = new Skill("history", "int");
        this.inv = new Skill("investigation", "int");
        this.nat = new Skill("nature", "int");
        this.rel = new Skill("religion", "int");
        this.ani = new Skill("animal handling", "wis");
        this.ins = new Skill("insight", "wis");
        this.med = new Skill("medicine", "wis");
        this.per = new Skill("perception", "wis");
        this.sur = new Skill("survival", "wis");
        this.dec = new Skill("deception", "cha");
        this.int = new Skill("intimidation", "cha");
        this.perf = new Skill("performance", "cha");
        this.pers = new Skill("persuasion", "cha");
        if (skills != null) {
            Object.entries(skills).forEach(([k, v]) => {
                this[k].proficiency = new Proficiency(v.proficiency.bonus);
            });
        }
    }
}
